import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save, Upload, Book } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminBookForm = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [formData, setFormData] = useState({
    Book_ID: '',
    Title_English: '',
    Title_Arabic: '',
    Author: '',
    Publication_Year: '',
    Description: ''
  });

  useEffect(() => {
    if (id) {
      AdminService.getBookById(id).then((res: any) => {
        setFormData(res.data);
      });
    }
  }, [id]);

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      await AdminService.upsertBook(formData);
      toast.success(id ? "Volume Updated" : "Volume Logged");
      navigate('/admin/books');
    } catch (err) { toast.error("System Fault"); }
    finally { setLoading(false); }
  };

  const handleExcelImport = async () => {
    if (!file) return toast.error("Select file");
    setLoading(true);
    try {
      await AdminService.importData('book', file);
      toast.success("Library Sync Success");
      navigate('/admin/books');
    } catch (err) { toast.error("Import Failed"); }
    finally { setLoading(false); }
  };

  return (
    <div className="max-w-6xl mx-auto p-8 space-y-10">
      <button onClick={() => navigate(-1)} className="flex items-center gap-2 text-gray-400 font-bold text-[10px] uppercase tracking-widest hover:text-primary transition-colors">
        <ArrowLeft size={14} /> Library
      </button>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
        <div className="lg:col-span-2 bg-white dark:bg-[#0f0f0f] p-10 rounded-[3rem] border border-gray-100 dark:border-white/5">
          <h2 className="text-3xl font-black italic uppercase mb-8">{id ? 'Edit' : 'Register'} <span className="text-primary">Book</span></h2>
          <form onSubmit={handleManualSubmit} className="grid grid-cols-2 gap-6">
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Book ID</label>
              <input value={formData.Book_ID} onChange={e => setFormData({...formData, Book_ID: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" placeholder="BK-001" required disabled={!!id} />
            </div>
            <div className="col-span-1 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Title (EN)</label>
              <input value={formData.Title_English} onChange={e => setFormData({...formData, Title_English: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white" required />
            </div>
            <div className="col-span-2 space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400 ml-2">Description</label>
              <textarea value={formData.Description} onChange={e => setFormData({...formData, Description: e.target.value})} className="w-full bg-gray-50 dark:bg-white/5 p-4 rounded-2xl dark:text-white h-32" />
            </div>
            <button type="submit" className="col-span-2 bg-black text-white py-5 rounded-2xl font-black uppercase tracking-widest hover:bg-primary transition-all">Commit Book</button>
          </form>
        </div>

        {!id && (
          <div className="bg-white dark:bg-[#0f0f0f] p-8 rounded-[3rem] border border-gray-100 dark:border-white/5 h-fit text-center">
            <Upload className="mx-auto text-primary mb-4" size={32} />
            <h3 className="text-xs font-black uppercase italic mb-4">Bulk Import</h3>
            <input type="file" onChange={e => setFile(e.target.files?.[0] || null)} className="mb-4 text-[10px]" />
            <button onClick={handleExcelImport} className="w-full bg-gray-50 dark:bg-white/5 py-4 rounded-2xl text-[10px] font-black uppercase hover:bg-black hover:text-white transition-all">Start Import</button>
          </div>
        )}
      </div>
    </div>
  );
};
